108	  // Integration: Long-standing customer's second contract
109	  it.todo("3-year customer's second contract: cursed sword (steel, ench 7) yields premium 160 G");
110	
111	  // CLAIM PROCESSING — basic
112	  it.todo("standard sword damage 500 G yields payout 400 G (500 - 100 deductible)");
113	  it.todo("rune damage 200 G yields payout 100 G (200 - 100 deductible, no special clauses)");
114	
115	  // Claim payout rounding
116	  it.todo("payout of 350.5 G is rounded DOWN to 350 G");
117	
118	  // Deductible per damage event
119	  it.todo("dragon attack damages sword (500) and amulet (300): payout 600 G (deductible applies once per item)");
120	
121	  // Special reimbursement clauses
122	  it.todo("steel sword with enchantment 9, damage 1000 G: payout 400 G (50% then deductible)");
123	  it.todo("dragon-material sword with enchantment 5, damage 800 G: payout 700 G (full reimbursement then deductible)");
124	  it.todo("dragon-material sword with enchantment 9, damage 1000 G: payout 400 G (50% wins, then deductible)");
125	  it.todo("dragon-material sword with enchantment exactly 8, damage 1000 G: payout 400 G (high-enchantment clause applies)");
126	
