1	export type Customer = {
2	  yearsWithMHPCO: number;
3	  previousContracts: number;
4	};
5	
6	export type Item = {
7	  type: string;
8	  cursed?: boolean;
9	  enchantment?: number;
10	};
11	
12	const PROCESSING_FEE = 5;
13	
14	const BASE_PREMIUMS: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	  moonstone: 25,
21	};
22	
23	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
24	const BLOCK_SIZE = 3;
25	const BLOCK_PREMIUM = 60;
26	const CURSE_SURCHARGE_RATE = 0.5;
27	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
28	const HIGH_ENCHANTMENT_THRESHOLD = 5;
29	const FIRST_INSURANCE_RATE = 0.1;
30	
31	function itemSurcharge(item: Item): number {
32	  const itemBase = BASE_PREMIUMS[item.type];
33	  let surcharge = 0;
34	  if (item.cursed) surcharge += itemBase * CURSE_SURCHARGE_RATE;
35	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
36	    surcharge += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
37	  }
38	  return surcharge;
39	}
40	
41	function typeSubtotal(type: string, count: number): number {
42	  const isBlock = COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
43	  return isBlock ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
44	}
45	
46	export function quote(customer: Customer, items: Item[]): number {
47	  const countsByType: Record<string, number> = {};
48	  for (const item of items) {
49	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
50	  }
51	
52	  const policyBase = Object.entries(countsByType)
53	    .reduce((sum, [type, count]) => sum + typeSubtotal(type, count), 0);
54	
55	  const itemSurcharges = items.reduce((sum, item) => sum + itemSurcharge(item), 0);
56	
57	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
58	  return Math.ceil(policyBase + itemSurcharges + firstInsurance) + PROCESSING_FEE;
59	}
